7860	  \mathlibok
7861	  \textit{Provided by Mathlib.}
7862	  For a morphism \(f : X \to Y\), an \(\mathcal{O}_X\)-module \(\mathcal{M}\), and an open
7863	  \(U \subseteq Y\), the sections of the pushforward \(f_*\mathcal{M}\) over \(U\) coincide
7864	  definitionally with the sections of \(\mathcal{M}\) over the preimage:
7865	  \(\Gamma(U, f_*\mathcal{M}) = \Gamma(f^{-1}(U), \mathcal{M})\).
7866	\end{lemma}
